import{_ as d,o as e,c as r,ag as a}from"./chunks/framework.DmWB24NN.js";const p=JSON.parse('{"title":"CHAPTER 1: ABILITY SCORES","description":"","frontmatter":{},"headers":[],"relativePath":"Book I - Core Rules/B01 - Chapter 01_ Ability Scores.md","filePath":"Book I - Core Rules/B01 - Chapter 01_ Ability Scores.md"}'),s={name:"Book I - Core Rules/B01 - Chapter 01_ Ability Scores.md"};function o(n,t,i,l,h,c){return e(),r("div",null,[...t[0]||(t[0]=[a('<h1 id="chapter-1-ability-scores" tabindex="-1"><strong>CHAPTER 1: ABILITY SCORES</strong> <a class="header-anchor" href="#chapter-1-ability-scores" aria-label="Permalink to &quot;**CHAPTER 1: ABILITY SCORES**&quot;">​</a></h1><p>Every character is built on six numbers. Three are physical (Strength, Dexterity, Constitution) and three are mental (Intelligence, Wisdom, Charisma). Together, they determine what a character can do, what they resist, and who they are before a single choice is made at the table.</p><p>Scores for most characters fall between 3 and 18. The human average runs 9–11. Ancestry adjustments can push scores outside that range; the entry for each ancestry specifies its minimums, maximums, and adjustments.</p><p>Ability scores have two functions: they produce modifiers that apply directly to combat rolls, hit points, and saving throws, and they set the target number for ability checks. How checks work is covered in Chapter 6: Skills.</p><hr><h2 id="generating-ability-scores" tabindex="-1"><strong>Generating Ability Scores</strong> <a class="header-anchor" href="#generating-ability-scores" aria-label="Permalink to &quot;**Generating Ability Scores**&quot;">​</a></h2><p>The method the table chooses here shapes the kind of game you end up playing. Agree on one before anyone picks up dice.</p><p><strong>Method I — Standard.</strong> Roll 4d6 and discard the lowest die. Repeat six times. Assign the six results to the six ability scores in any order.</p><ul><li>The recommended method. The average result per score lands around 12, with real variance — characters will have genuine strengths and genuine gaps. The assignment step is where the character begins to take shape: deciding where a 15 goes matters, and so does deciding where a 7 goes.</li></ul><p><strong>Method II — Traditional.</strong> Roll 3d6 six times, in order: Strength, Dexterity, Constitution, Intelligence, Wisdom, Charisma. Record each result as it falls.</p><ul><li>Fortune shapes these characters, not assignment. Scores can fall anywhere from 3 to 18 in an order the player didn&#39;t choose. Class minimum requirements apply regardless — a player who cannot meet them on a first pass may reroll a single score once, if the table agrees to this before anyone rolls. Some groups find the pressure of a constrained character worth it. Others find it an obstacle that contributes nothing to the fiction. Know which table you&#39;re running before committing to this method.</li></ul><p><strong>Method III — Flexible.</strong> Roll 3d6 twelve times. Choose six of the twelve results and assign them in any order. Discard the rest.</p><ul><li>Statistically close to Method I, but the larger pool reduces the risk of an unplayable spread. A useful middle position for groups who want randomness without the harder edges of traditional rolling.</li></ul><p><strong>Method IV — Point Buy.</strong> Every ability score begins at 8. Distribute 30 points freely. No score may fall below 3 or be raised above 18. Increases above 15 carry a higher cost: 15 to 16 costs 2 points; 16 to 17 costs 3 points; 17 to 18 costs 4 points. All other increases cost 1 point per step.</p><ul><li>Fortune plays no part in this method. Characters arrive at the table fully formed. Point buy suits groups who come in with a concept already decided and want the ability scores to execute it without interference — but it produces characters who rarely surprise their players, and almost never surprise the GM running them.</li></ul><p>After generation and before ancestry selection, no score may exceed 18 — except through ancestry adjustments or exceptional strength, which applies to warriors only.</p><hr><h2 id="strength" tabindex="-1"><strong>STRENGTH</strong> <a class="header-anchor" href="#strength" aria-label="Permalink to &quot;**STRENGTH**&quot;">​</a></h2><p>Strength governs raw physical force: how hard a blow lands, how much weight a character carries, and whether a shoulder against a stuck door does anything. It is the primary ability score for warriors, and the one score that can meaningfully exceed 18 through normal play.</p><h3 id="table-1-1-strength" tabindex="-1"><strong>Table 1.1: Strength</strong> <a class="header-anchor" href="#table-1-1-strength" aria-label="Permalink to &quot;**Table 1.1: Strength**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Score</th><th>Attack Mod</th><th>Damage Mod</th><th>No-Enc (kg)</th><th>Max (kg)</th><th>Force Doors</th><th>Bend Bars</th></tr></thead><tbody><tr><td>1</td><td>−5</td><td>−4</td><td>0.5</td><td>1.5</td><td>1</td><td>0%</td></tr><tr><td>2</td><td>−3</td><td>−2</td><td>0.5</td><td>2.5</td><td>1</td><td>0%</td></tr><tr><td>3</td><td>−3</td><td>−1</td><td>2.5</td><td>4.5</td><td>2</td><td>0%</td></tr><tr><td>4–5</td><td>−2</td><td>−1</td><td>4.5</td><td>9</td><td>3</td><td>0%</td></tr><tr><td>6–7</td><td>−1</td><td>0</td><td>9</td><td>25</td><td>4</td><td>0%</td></tr><tr><td>8–9</td><td>0</td><td>0</td><td>16</td><td>41</td><td>5</td><td>1%</td></tr><tr><td>10–11</td><td>0</td><td>0</td><td>18</td><td>52</td><td>6</td><td>2%</td></tr><tr><td>12–13</td><td>0</td><td>0</td><td>20</td><td>61</td><td>7</td><td>4%</td></tr><tr><td>14–15</td><td>0</td><td>0</td><td>25</td><td>74</td><td>8</td><td>7%</td></tr><tr><td>16</td><td>0</td><td>+1</td><td>32</td><td>81</td><td>9</td><td>10%</td></tr><tr><td>17</td><td>+1</td><td>+1</td><td>38</td><td>99</td><td>10</td><td>13%</td></tr><tr><td>18</td><td>+1</td><td>+2</td><td>50</td><td>115</td><td>11</td><td>16%</td></tr><tr><td>18/01–50</td><td>+1</td><td>+3</td><td>61</td><td>126</td><td>12</td><td>20%</td></tr><tr><td>18/51–75</td><td>+2</td><td>+3</td><td>72</td><td>140</td><td>13</td><td>25%</td></tr><tr><td>18/76–90</td><td>+2</td><td>+4</td><td>83</td><td>150</td><td>14</td><td>30%</td></tr><tr><td>18/91–99</td><td>+2</td><td>+5</td><td>105</td><td>170</td><td>15 (3)</td><td>35%</td></tr><tr><td>18/00</td><td>+3</td><td>+6</td><td>150</td><td>215</td><td>16 (6)</td><td>40%</td></tr><tr><td>19</td><td>+3</td><td>+7</td><td>220</td><td>290</td><td>16 (8)</td><td>50%</td></tr><tr><td>20</td><td>+3</td><td>+8</td><td>240</td><td>315</td><td>17 (10)</td><td>60%</td></tr><tr><td>21</td><td>+4</td><td>+9</td><td>285</td><td>365</td><td>17 (12)</td><td>70%</td></tr><tr><td>22</td><td>+4</td><td>+10</td><td>355</td><td>435</td><td>18 (14)</td><td>80%</td></tr><tr><td>23</td><td>+5</td><td>+11</td><td>420</td><td>510</td><td>18 (16)</td><td>90%</td></tr><tr><td>24</td><td>+6</td><td>+12</td><td>555</td><td>650</td><td>19 (17)</td><td>95%</td></tr><tr><td>25</td><td>+7</td><td>+14</td><td>690</td><td>790</td><td>19 (18)</td><td>99%</td></tr></tbody></table><p><em>Force Doors: roll 1d20 equal to or under the listed number. The value in parentheses applies to locked, barred, or magically held doors.</em></p><p><strong>Attack Modifier.</strong> Added to the attack roll for melee weapons and bows. See Chapter 7: Combat and Chapter 9: Weapons &amp; Armor for bow specifics.</p><p><strong>Damage Modifier.</strong> Added to damage for melee weapons, hurled weapons, and bows. Crossbows are excluded regardless of Strength score.</p><p><strong>No-Encumbered.</strong> Maximum weight in kilograms carried without encumbrance effects. See Chapter 7: Equipment.</p><p><strong>Max Weight.</strong> Absolute carrying capacity. A character bearing more than this cannot move.</p><p><strong>Force Doors.</strong> To force open a large or stuck door, roll 1d20. A result equal to or under the listed number succeeds. The value in parentheses applies to locked, barred, or magically held doors. A failed attempt cannot be retried on the same door.</p><p><strong>Bend Bars/Lift Portcullis.</strong> The percentage chance to bend iron bars, lift a portcullis, or perform a comparable feat of raw power. Roll percentile dice.</p><h3 id="exceptional-strength" tabindex="-1"><strong>Exceptional Strength</strong> <a class="header-anchor" href="#exceptional-strength" aria-label="Permalink to &quot;**Exceptional Strength**&quot;">​</a></h3><p>A warrior whose Strength reaches 18 rolls a d% immediately and records both values — for example, 18/43. The percentile determines where on the extended portion of the table the warrior falls. 18/61 outperforms 18/35 in every column. No other class qualifies for exceptional strength.</p><p><strong>Bonuses and penalties.</strong> When a spell, magic item, or curse raises or lowers a warrior&#39;s Strength, each point of change moves the exceptional strength score one category up or down, landing in the middle of the new range. Ancestry modifiers applied at character creation do not trigger this rule. The movement points between each category:</p><ul><li>18/01–50: a bonus rises to 18/51; a penalty drops to standard 18.</li><li>18/51–75: a bonus rises to 18/76; a penalty drops to 18/50.</li><li>18/76–90: a bonus rises to 18/91; a penalty drops to 18/75.</li><li>18/91–99: a bonus rises to 18/00; a penalty drops to 18/90.</li><li>18/00: a bonus rises to 19; a penalty drops to 18/95.</li></ul><hr><h2 id="dexterity" tabindex="-1"><strong>DEXTERITY</strong> <a class="header-anchor" href="#dexterity" aria-label="Permalink to &quot;**DEXTERITY**&quot;">​</a></h2><p>Dexterity measures quickness and precision — hand-eye coordination, reaction speed, and the body&#39;s capacity for evasion. It is the primary ability score for rogues, but its effect on Armor Class makes it meaningful for every class.</p><h3 id="table-1-2-dexterity" tabindex="-1"><strong>Table 1.2: Dexterity</strong> <a class="header-anchor" href="#table-1-2-dexterity" aria-label="Permalink to &quot;**Table 1.2: Dexterity**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Score</th><th>Surprise Mod</th><th>Missile Attack Mod</th><th>AC Modifier</th></tr></thead><tbody><tr><td>1</td><td>−6</td><td>−6</td><td>−5</td></tr><tr><td>2</td><td>−4</td><td>−4</td><td>−5</td></tr><tr><td>3</td><td>−3</td><td>−3</td><td>−4</td></tr><tr><td>4</td><td>−2</td><td>−2</td><td>−3</td></tr><tr><td>5</td><td>−1</td><td>−1</td><td>−2</td></tr><tr><td>6–8</td><td>0</td><td>0</td><td>−1</td></tr><tr><td>9–14</td><td>0</td><td>0</td><td>0</td></tr><tr><td>15</td><td>0</td><td>0</td><td>+1</td></tr><tr><td>16</td><td>+1</td><td>+1</td><td>+2</td></tr><tr><td>17</td><td>+2</td><td>+2</td><td>+3</td></tr><tr><td>18</td><td>+2</td><td>+2</td><td>+3</td></tr><tr><td>19</td><td>+3</td><td>+3</td><td>+4</td></tr><tr><td>20–21</td><td>+3</td><td>+3</td><td>+4</td></tr><tr><td>21–23</td><td>+4</td><td>+4</td><td>+5</td></tr><tr><td>24–25</td><td>+5</td><td>+5</td><td>+6</td></tr></tbody></table><p><em>AC Modifier: positive values add to Armor Class (better defense); negative values subtract from it (worse defense). A character who cannot react to their situation — surprised, prone, paralyzed, sleeping, or restrained — does not benefit from a positive modifier.</em></p><p><strong>Surprise Modifier.</strong> Applied to surprise rolls. Also applies to Reflex saves — saves against effects that quick movement can avoid, such as area spells and breath weapons. See Chapter 8: Saving Throws.</p><p><strong>Missile Attack Modifier.</strong> Applied to all ranged attack rolls. Also reduces penalties incurred when attacking with a second weapon.</p><p><strong>AC Modifier.</strong> Added directly to Armor Class. See note above on reactive conditions.</p><hr><h2 id="constitution" tabindex="-1"><strong>CONSTITUTION</strong> <a class="header-anchor" href="#constitution" aria-label="Permalink to &quot;**CONSTITUTION**&quot;">​</a></h2><p>Constitution measures physical endurance: the body&#39;s capacity to absorb punishment, shake off poison and disease, and survive trauma. Every class benefits from it.</p><p>A character&#39;s base Constitution score is the maximum number of times they can be resurrected. Each resurrection reduces that count by one. The count does not recover.</p><p>The Fortitude save — against poison, disease, death magic, and direct physical trauma — is set equal to Constitution at character creation and advances separately thereafter. See Chapter 8: Saving Throws.</p><h3 id="table-1-3-constitution" tabindex="-1"><strong>Table 1.3: Constitution</strong> <a class="header-anchor" href="#table-1-3-constitution" aria-label="Permalink to &quot;**Table 1.3: Constitution**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Score</th><th>HP Modifier</th><th>System Shock</th><th>Resurrection</th><th>Poison Resist</th><th>Regeneration</th></tr></thead><tbody><tr><td>3</td><td>−2</td><td>25%</td><td>30%</td><td>−2</td><td>—</td></tr><tr><td>4</td><td>−1</td><td>30%</td><td>35%</td><td>−1</td><td>—</td></tr><tr><td>5</td><td>−1</td><td>35%</td><td>40%</td><td>0</td><td>—</td></tr><tr><td>6</td><td>0</td><td>40%</td><td>45%</td><td>0</td><td>—</td></tr><tr><td>7</td><td>0</td><td>55%</td><td>60%</td><td>0</td><td>—</td></tr><tr><td>8</td><td>0</td><td>60%</td><td>65%</td><td>0</td><td>—</td></tr><tr><td>9</td><td>0</td><td>65%</td><td>70%</td><td>0</td><td>—</td></tr><tr><td>10</td><td>0</td><td>70%</td><td>75%</td><td>0</td><td>—</td></tr><tr><td>11</td><td>0</td><td>75%</td><td>80%</td><td>0</td><td>—</td></tr><tr><td>12</td><td>0</td><td>80%</td><td>85%</td><td>0</td><td>—</td></tr><tr><td>13</td><td>0</td><td>85%</td><td>90%</td><td>0</td><td>—</td></tr><tr><td>14</td><td>0</td><td>88%</td><td>92%</td><td>0</td><td>—</td></tr><tr><td>15</td><td>+1</td><td>90%</td><td>94%</td><td>0</td><td>—</td></tr><tr><td>16</td><td>+2 *</td><td>95%</td><td>96%</td><td>0</td><td>—</td></tr><tr><td>17</td><td>+3</td><td>97%</td><td>98%</td><td>0</td><td>—</td></tr><tr><td>18</td><td>+4</td><td>99%</td><td>100%</td><td>0</td><td>—</td></tr><tr><td>19</td><td>+5</td><td>99%</td><td>100%</td><td>+1</td><td>—</td></tr><tr><td>20</td><td>+5 **</td><td>99%</td><td>100%</td><td>+1</td><td>1/6 turns</td></tr><tr><td>21</td><td>+6 ***</td><td>99%</td><td>100%</td><td>+2</td><td>1/5 turns</td></tr><tr><td>22</td><td>+6 ***</td><td>99%</td><td>100%</td><td>+2</td><td>1/4 turns</td></tr><tr><td>23</td><td>+6 ***</td><td>99%</td><td>100%</td><td>+3</td><td>1/3 turns</td></tr><tr><td>24</td><td>+7 ****</td><td>99%</td><td>100%</td><td>+3</td><td>1/2 turns</td></tr><tr><td>25</td><td>+7 ****</td><td>100%</td><td>100%</td><td>+4</td><td>1 turn</td></tr></tbody></table><p>* Maximum HP modifier for non-warrior classes, regardless of actual Constitution score. ** Minimum result of 2 on any hit die. *** Minimum result of 3 on any hit die. **** Minimum result of 4 on any hit die.</p><p><strong>HP Modifier.</strong> Added to each hit die rolled when determining hit points. The roll always yields a minimum of 1 HP regardless of the modifier. Non-warrior classes apply no more than +2, regardless of actual Constitution score.</p><p>When Constitution changes permanently, hit points adjust: multiply the new HP modifier by the character&#39;s current number of hit dice, then add or subtract the difference from the previous modifier&#39;s total. This calculation can reduce current hit points to zero or below, which can kill the character.</p><p><strong>System Shock.</strong> The percentage chance of surviving a sudden physical transformation — polymorph, petrification, and similar effects. Roll percentile dice; surviving requires rolling equal to or under the listed percentage. A character who fails a System Shock roll when returning to their original form also dies.</p><p><strong>Resurrection Chance.</strong> The percentage chance that a resurrection attempt succeeds. The caster makes this roll.</p><p><strong>Poison Resistance.</strong> A modifier applied to saving throws against poison.</p><p><strong>Regeneration.</strong> Available only at Constitution scores attainable through magic or exceptional ancestry traits. The character recovers the listed number of hit points per turn. This does not regenerate severed limbs unless specified by the source granting it.</p><hr><h2 id="intelligence" tabindex="-1"><strong>INTELLIGENCE</strong> <a class="header-anchor" href="#intelligence" aria-label="Permalink to &quot;**INTELLIGENCE**&quot;">​</a></h2><p>Intelligence measures what a character has learned and retained: languages, scholarly knowledge, and the cognitive foundation that arcane magic requires. It is the primary ability score for wizards, governing how many spells they can learn and how powerful those spells can be.</p><p>A low Intelligence score means a character grew up without access to formal education, books, or scholarly training — not that they lack competence, judgment, or courage. A brilliant fighter who never learned to read has Intelligence 6. A well-read but street-naive scholar has Wisdom 6. These measure different things.</p><p>Intelligence has no associated saving throw. Resisting magical influence on the mind belongs to willpower and perception — that is, Wisdom&#39;s domain, and the Will save.</p><h3 id="table-1-4-intelligence" tabindex="-1"><strong>Table 1.4: Intelligence</strong> <a class="header-anchor" href="#table-1-4-intelligence" aria-label="Permalink to &quot;**Table 1.4: Intelligence**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Score</th><th>Extra Languages</th><th>Max Spell Level</th><th>Max Spells/Level</th><th>Learn Spell</th><th>Illusion Immunity</th></tr></thead><tbody><tr><td>1</td><td>0</td><td>—</td><td>—</td><td>—</td><td>—</td></tr><tr><td>2–8</td><td>1</td><td>—</td><td>—</td><td>—</td><td>—</td></tr><tr><td>9</td><td>2</td><td>4th</td><td>6</td><td>35%</td><td>—</td></tr><tr><td>10</td><td>2</td><td>5th</td><td>7</td><td>40%</td><td>—</td></tr><tr><td>11</td><td>2</td><td>5th</td><td>7</td><td>45%</td><td>—</td></tr><tr><td>12</td><td>3</td><td>6th</td><td>7</td><td>50%</td><td>—</td></tr><tr><td>13</td><td>3</td><td>6th</td><td>9</td><td>55%</td><td>—</td></tr><tr><td>14</td><td>4</td><td>7th</td><td>9</td><td>60%</td><td>—</td></tr><tr><td>15</td><td>4</td><td>7th</td><td>11</td><td>65%</td><td>—</td></tr><tr><td>16</td><td>5</td><td>8th</td><td>11</td><td>70%</td><td>—</td></tr><tr><td>17</td><td>6</td><td>8th</td><td>14</td><td>75%</td><td>—</td></tr><tr><td>18</td><td>7</td><td>9th</td><td>18</td><td>85%</td><td>—</td></tr><tr><td>19</td><td>8</td><td>9th</td><td>24</td><td>95%</td><td>1st-level illusions</td></tr><tr><td>20</td><td>9</td><td>9th</td><td>30</td><td>96%</td><td>2nd-level illusions</td></tr><tr><td>21</td><td>10</td><td>9th</td><td>30</td><td>97%</td><td>3rd-level illusions</td></tr><tr><td>22</td><td>11</td><td>9th</td><td>30</td><td>98%</td><td>4th-level illusions</td></tr><tr><td>23</td><td>12</td><td>9th</td><td>30</td><td>99%</td><td>5th-level illusions</td></tr><tr><td>24</td><td>15</td><td>9th</td><td>30</td><td>100%</td><td>6th-level illusions</td></tr><tr><td>25</td><td>20</td><td>9th</td><td>30</td><td>100%</td><td>7th-level illusions</td></tr></tbody></table><p><strong>Extra Languages.</strong> All characters begin play knowing Common. Non-human characters also speak their ancestral language at no cost. This column indicates the number of additional languages the character may learn. At Intelligence 1, communication is limited to gesture and sound.</p><p><strong>Max Spell Level.</strong> The highest level of wizard spell this Intelligence score supports. A wizard whose Intelligence falls below the threshold for a known spell retains that spell but cannot learn new spells of that level.</p><p><strong>Max Spells Per Level.</strong> The maximum number of wizard spells that can be learned per spell level. At score 21 and above, beings of demigod status or higher have no upper limit.</p><p><strong>Learn Spell.</strong> The percentage chance a wizard successfully learns a new spell from study. A failed roll cannot be retried until the wizard gains a level.</p><p><strong>Illusion Immunity.</strong> Characters with Intelligence 19 or higher see through illusions up to the listed level automatically — no roll required. Immunities are cumulative across all qualifying thresholds.</p><hr><h2 id="wisdom" tabindex="-1"><strong>WISDOM</strong> <a class="header-anchor" href="#wisdom" aria-label="Permalink to &quot;**WISDOM**&quot;">​</a></h2><p>Wisdom measures judgment, perceptiveness, and strength of will — the qualities that distinguish someone who understands a situation from someone who merely survives it. Priests draw on it for divine spellcasting. Every character draws on it for one of the most important defenses in the game.</p><p>The Will save — against charm, fear, mental influence, and most spells targeting the mind — is set equal to Wisdom at character creation and advances separately thereafter. See Chapter 8: Saving Throws.</p><h3 id="table-1-5-wisdom" tabindex="-1"><strong>Table 1.5: Wisdom</strong> <a class="header-anchor" href="#table-1-5-wisdom" aria-label="Permalink to &quot;**Table 1.5: Wisdom**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Score</th><th>Mental Defense Mod</th><th>Bonus Spells</th><th>Spell Failure</th><th>Spell Immunity</th></tr></thead><tbody><tr><td>1</td><td>0</td><td>—</td><td>80%</td><td>—</td></tr><tr><td>2</td><td>0</td><td>—</td><td>60%</td><td>—</td></tr><tr><td>3</td><td>0</td><td>—</td><td>50%</td><td>—</td></tr><tr><td>4</td><td>0</td><td>—</td><td>45%</td><td>—</td></tr><tr><td>5</td><td>0</td><td>—</td><td>40%</td><td>—</td></tr><tr><td>6</td><td>0</td><td>—</td><td>35%</td><td>—</td></tr><tr><td>7</td><td>0</td><td>—</td><td>30%</td><td>—</td></tr><tr><td>8</td><td>0</td><td>—</td><td>25%</td><td>—</td></tr><tr><td>9</td><td>0</td><td>—</td><td>20%</td><td>—</td></tr><tr><td>10</td><td>0</td><td>—</td><td>15%</td><td>—</td></tr><tr><td>11</td><td>0</td><td>—</td><td>10%</td><td>—</td></tr><tr><td>12</td><td>0</td><td>—</td><td>5%</td><td>—</td></tr><tr><td>13</td><td>0</td><td>1st</td><td>0%</td><td>—</td></tr><tr><td>14</td><td>0</td><td>1st</td><td>0%</td><td>—</td></tr><tr><td>15</td><td>+1</td><td>2nd</td><td>0%</td><td>—</td></tr><tr><td>16</td><td>+2</td><td>2nd</td><td>0%</td><td>—</td></tr><tr><td>17</td><td>+3</td><td>3rd</td><td>0%</td><td>—</td></tr><tr><td>18</td><td>+4</td><td>4th</td><td>0%</td><td>—</td></tr><tr><td>19</td><td>+4</td><td>1st, 4th</td><td>0%</td><td>Cause Fear, Charm, Command, Friends, Hypnotism</td></tr><tr><td>20</td><td>+4</td><td>2nd, 4th</td><td>0%</td><td>Forget, Hold Person, Ray of Enfeeblement, Scare</td></tr><tr><td>21</td><td>+4</td><td>3rd, 5th</td><td>0%</td><td>Fear</td></tr><tr><td>22</td><td>+4</td><td>4th, 5th</td><td>0%</td><td>Charm Monster, Confusion, Emotion, Fumble, Suggestion</td></tr><tr><td>23</td><td>+4</td><td>5th, 5th</td><td>0%</td><td>Chaos, Feeblemind, Hold Monster, Magic Jar, Quest</td></tr><tr><td>24</td><td>+4</td><td>6th, 6th</td><td>0%</td><td>Geas, Mass Suggestion, Rod of Rulership</td></tr><tr><td>25</td><td>+4</td><td>6th, 7th</td><td>0%</td><td>Antipathy/Sympathy, Death Spell, Mass Charm</td></tr></tbody></table><p><em>Bonus Spells: available to priests only. Each listed spell level grants one additional spell slot per day at that level. Bonuses are cumulative — a Wisdom of 19 grants both the 1st-level and 4th-level bonus.</em></p><p><strong>Mental Defense Modifier.</strong> Applied to Will saves — saving throws against spells and effects targeting the mind, including charm and fear.</p><p><strong>Bonus Spells.</strong> Priests with Wisdom 13 or higher gain additional spell slots. Each entry grants one extra slot at the listed level per day. The bonuses stack: Wisdom 19 grants two bonus slots (one 1st-level and one 4th-level), not one.</p><p><strong>Spell Failure.</strong> Priests with Wisdom below 13 have a chance of spell failure on each casting. Roll percentile dice before casting; a result under the listed percentage means the spell is lost without effect.</p><p><strong>Spell Immunity.</strong> High Wisdom confers automatic immunity to specific spells. Immunity is cumulative — every effect listed for lower scores applies at higher ones as well.</p><hr><h2 id="charisma" tabindex="-1"><strong>CHARISMA</strong> <a class="header-anchor" href="#charisma" aria-label="Permalink to &quot;**CHARISMA**&quot;">​</a></h2><p>Charisma measures personal presence: the quality that makes people listen, follow, or stay when the situation gives them reasons to go. It governs the number of permanent retainers a character can maintain, how those retainers hold under pressure, and the initial reaction of strangers.</p><p>Physical appearance may contribute to Charisma, but it is neither required nor sufficient. A scarred veteran who commands rooms through authority has high Charisma. A handsome noble who visibly hesitates may not.</p><h3 id="table-1-6-charisma" tabindex="-1"><strong>Table 1.6: Charisma</strong> <a class="header-anchor" href="#table-1-6-charisma" aria-label="Permalink to &quot;**Table 1.6: Charisma**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Score</th><th>Max Henchmen</th><th>Loyalty Mod</th><th>Reaction Mod</th></tr></thead><tbody><tr><td>1</td><td>0</td><td>−8</td><td>−7</td></tr><tr><td>2</td><td>1</td><td>−7</td><td>−6</td></tr><tr><td>3</td><td>1</td><td>−6</td><td>−5</td></tr><tr><td>4</td><td>1</td><td>−5</td><td>−4</td></tr><tr><td>5</td><td>2</td><td>−4</td><td>−3</td></tr><tr><td>6</td><td>2</td><td>−3</td><td>−2</td></tr><tr><td>7</td><td>3</td><td>−2</td><td>−1</td></tr><tr><td>8</td><td>3</td><td>−1</td><td>0</td></tr><tr><td>9–11</td><td>4</td><td>0</td><td>0</td></tr><tr><td>12</td><td>5</td><td>0</td><td>0</td></tr><tr><td>13</td><td>5</td><td>0</td><td>+1</td></tr><tr><td>14</td><td>6</td><td>+1</td><td>+2</td></tr><tr><td>15</td><td>7</td><td>+3</td><td>+3</td></tr><tr><td>16</td><td>8</td><td>+4</td><td>+5</td></tr><tr><td>17</td><td>10</td><td>+6</td><td>+6</td></tr><tr><td>18</td><td>15</td><td>+8</td><td>+7</td></tr><tr><td>19</td><td>20</td><td>+10</td><td>+8</td></tr><tr><td>20</td><td>25</td><td>+12</td><td>+9</td></tr><tr><td>21</td><td>30</td><td>+14</td><td>+10</td></tr><tr><td>22</td><td>35</td><td>+16</td><td>+11</td></tr><tr><td>23</td><td>40</td><td>+18</td><td>+12</td></tr><tr><td>24</td><td>45</td><td>+20</td><td>+13</td></tr><tr><td>25</td><td>50</td><td>+20</td><td>+14</td></tr></tbody></table><p><strong>Maximum Henchmen.</strong> The number of NPCs who may serve as permanent retainers. This does not limit hirelings, who are paid labor under contract rather than followers by choice.</p><p><strong>Loyalty Modifier.</strong> Applied to henchman loyalty checks. High Charisma keeps retainers from deserting when conditions deteriorate; low Charisma means they need less reason to go.</p><p><strong>Reaction Modifier.</strong> Applied to random reaction rolls when first encountering NPCs. Positive modifiers improve initial disposition; negative modifiers worsen it.</p><hr><h2 id="ancestry-requirements-and-adjustments" tabindex="-1"><strong>Ancestry Requirements and Adjustments</strong> <a class="header-anchor" href="#ancestry-requirements-and-adjustments" aria-label="Permalink to &quot;**Ancestry Requirements and Adjustments**&quot;">​</a></h2><p>Non-human ancestries have minimum and maximum score requirements and permanent adjustments. Requirements are checked against raw, unadjusted scores generated during character creation — before any ancestry modifier is applied. If a raw score falls outside the required range for a chosen ancestry, that ancestry is unavailable.</p><p>Once the choice is confirmed, apply the ancestry adjustments permanently. Ancestry bonuses can push a score above 18; the ceiling that applies during score generation does not apply here.</p><p>Two ancestries — Badaki and Ûrgon — carry an additional prerequisite: the character must have a minimum of 13 in both Strength and Constitution before adjustments. Both minimums must be met simultaneously. A character with Strength 15 and Constitution 11 does not qualify, regardless of how close the shortfall is.</p><p>Human characters have no requirements. Any set of rolled scores qualifies, and no modifiers apply.</p><h3 id="size" tabindex="-1"><strong>Size</strong> <a class="header-anchor" href="#size" aria-label="Permalink to &quot;**Size**&quot;">​</a></h3><p>Most player characters are medium-sized — human-scale, capable of passing through a standard doorway, purchasing armor at any garrison outfitter, and moving through a 1.5 m corridor without incident.</p><p>Ûrgon characters are large. In confined spaces — corridors narrower than 3 m, small rooms, standard dungeon passages, and any environment the GM judges similarly restrictive — large characters suffer a −2 penalty to attack rolls and Armor Class. Passing through an opening smaller than 1.5 m requires a full round and a successful Strength check. Armor for an Ûrgon must be custom-made, costs three times the listed price, and requires a craftsman who has worked with the ancestry before.</p><p>Badaki characters occupy the upper edge of medium. Their physical mass is reflected in their ability score profile, not in combat restrictions.</p><h3 id="natural-armor" tabindex="-1"><strong>Natural Armor</strong> <a class="header-anchor" href="#natural-armor" aria-label="Permalink to &quot;**Natural Armor**&quot;">​</a></h3><p>Badaki, Ûrgon, and Vartran possess natural armor — dense hide, layered muscle, or scales — that provides a base Armor Class without worn armor. Each ancestry&#39;s entry lists the natural armor AC value. When worn armor produces a better AC than the natural rating, use the worn armor. When it does not, the natural armor applies. The two values never combine.</p><h3 id="darkvision-and-infravision" tabindex="-1"><strong>Darkvision and Infravision</strong> <a class="header-anchor" href="#darkvision-and-infravision" aria-label="Permalink to &quot;**Darkvision and Infravision**&quot;">​</a></h3><p>Most non-human ancestries possess infravision: the ability to detect heat signatures in darkness, rendering warm-blooded creatures and heat sources visible at up to 18 m. Infravision does not allow a character to read, distinguish colors, or perceive cold objects clearly.</p><p>Duergar possess true darkvision. They see in complete darkness as clearly as a human sees in full daylight — full detail, cold objects included, no heat-signature limitation. The cost: Duergar eyes are calibrated to permanent underground conditions. In direct outdoor daylight, or its magical equivalent, they suffer a −2 penalty to all attack rolls, saving throws, and skill checks. This penalty disappears underground, indoors, or after dusk.</p><hr><h3 id="table-1-7-ancestry-ability-score-requirements" tabindex="-1"><strong>Table 1.7: Ancestry Ability Score Requirements</strong> <a class="header-anchor" href="#table-1-7-ancestry-ability-score-requirements" aria-label="Permalink to &quot;**Table 1.7: Ancestry Ability Score Requirements**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Score</th><th>Húldar</th><th>Aelár</th><th>Duardeen</th><th>Duergar</th><th>Badaki</th><th>Ûrgon</th><th>Vartran</th><th>Val&#39;arian</th></tr></thead><tbody><tr><td>Strength</td><td>3–18</td><td>3–18</td><td>8–18</td><td>8–18</td><td>13–20 †</td><td>13–20 †</td><td>8–20</td><td>3–17</td></tr><tr><td>Dexterity</td><td>6–19</td><td>6–19</td><td>2–17</td><td>2–16</td><td>3–16</td><td>2–14</td><td>3–16</td><td>8–19</td></tr><tr><td>Constitution</td><td>7–18</td><td>5–18</td><td>11–19</td><td>12–20</td><td>13–20 †</td><td>13–20 †</td><td>10–20</td><td>5–17</td></tr><tr><td>Intelligence</td><td>5–18</td><td>4–18</td><td>3–18</td><td>3–18</td><td>3–17</td><td>5–18</td><td>6–18</td><td>5–18</td></tr><tr><td>Wisdom</td><td>10–18</td><td>3–18</td><td>3–18</td><td>3–18</td><td>3–18</td><td>8–18</td><td>3–18</td><td>6–18</td></tr><tr><td>Charisma</td><td>3–18</td><td>6–18</td><td>3–17</td><td>2–14</td><td>3–16</td><td>6–18</td><td>3–18</td><td>6–18</td></tr></tbody></table><p>† Badaki and Ûrgon require a minimum of 13 in both Strength and Constitution before adjustments. Both minimums must be met simultaneously.</p><p>Human characters have no ability score requirements.</p><hr><h3 id="table-1-8-ancestry-ability-score-adjustments" tabindex="-1"><strong>Table 1.8: Ancestry Ability Score Adjustments</strong> <a class="header-anchor" href="#table-1-8-ancestry-ability-score-adjustments" aria-label="Permalink to &quot;**Table 1.8: Ancestry Ability Score Adjustments**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Ancestry</th><th>Adjustments</th></tr></thead><tbody><tr><td>Human</td><td>—</td></tr><tr><td>Húldar</td><td>+1 Wisdom, −1 Constitution</td></tr><tr><td>Aelár</td><td>+1 Dexterity, −1 Constitution</td></tr><tr><td>Duardeen</td><td>+1 Constitution, −1 Dexterity</td></tr><tr><td>Duergar</td><td>+1 Constitution, −1 Charisma</td></tr><tr><td>Badaki</td><td>+2 Strength, +1 Constitution, −1 Dexterity, −1 Intelligence</td></tr><tr><td>Ûrgon</td><td>+2 Strength, +1 Constitution, −2 Dexterity</td></tr><tr><td>Vartran</td><td>+1 Strength, +1 Constitution, −1 Dexterity</td></tr><tr><td>Val&#39;arian</td><td>+1 Dexterity, −1 Strength</td></tr></tbody></table><hr><p><em>Full trait descriptions for all non-human ancestries appear under their respective entries in Chapter 2.</em></p>',112)])])}const m=d(s,[["render",o]]);export{p as __pageData,m as default};
